com.mirth.connect.plugins.javascriptstep.script:
var snapshot = JSON.parse(msg);
channelMap.put('ts', snapshot.timestamp || new Date().toISOString());

var pump = snapshot.devices &&
           snapshot.devices.infusion_pump &&
           snapshot.devices.infusion_pump.readings
         ? snapshot.devices.infusion_pump.readings
         : {};

channelMap.put('pump', pump);
logger.info('Infusion pump snapshot parsed: ' + snapshot.timestamp +
            ' | status=' + (snapshot.devices.infusion_pump.status || 'unknown') +
            ' | flow=' + (pump.flow_rate_ml_h || 0) + ' ml/h');

// -----------------------------------------------------------------------
// HL7 v2.5.1 ORU^R01 — Infusion Pump Simulator (healthcare-v2)
//
// All OBX codes are LOCAL — no standardised LOINC panel exists for
// peristaltic IV infusion pumps at this level of detail.
// -----------------------------------------------------------------------
var p  = channelMap.get('pump') || {};
var ts = channelMap.get('ts')   || new Date().toISOString();

var hl7ts = ts.replace(/[-:T]/g,'').substring(0,14);
var msgId = 'PUMP' + hl7ts;

function v(field) {
  var val = p[field];
  return (val !== null && val !== undefined) ? val : '';
}

function obxNM(seq, code, name, value, unit, refRange) {
  return 'OBX|' + seq + '|NM|' + code + '^' + name + '^LOCAL||' +
    value + '|' + unit + '|' + refRange + '||||F|||' + hl7ts;
}
function obxST(seq, code, name, value) {
  return 'OBX|' + seq + '|ST|' + code + '^' + name + '^LOCAL||' +
    value + '||||||F|||' + hl7ts;
}

// alarm_flags is an array — join for HL7 ST field
var alarmStr = Array.isArray(p.alarm_flags) && p.alarm_flags.length > 0
  ? p.alarm_flags.join('~')
  : 'NONE';

var lines = [
  'MSH|^~\\&|INFUSION_PUMP|HOSPITAL_ICU|MIRTH_CONNECT|OPENEMR|' + hl7ts +
    '||ORU^R01^ORU_R01|' + msgId + '|P|2.5.1|||AL|AL|',
  'PID|1||PATIENT_001^^^HOSPITAL_ICU&HOSPITAL&L||Paciente^ICU||19800101|U|',
  'OBR|1|||PUMP-PANEL^Infusion Pump Parameters^LOCAL|||' + hl7ts + '|||||||||||||||F',

  // Status and mode
  obxST(1,  'PUMP-STATUS',   'Infusion status',           v('infusion_active') ? (v('kvo_mode') ? 'KVO' : 'INFUSING') : 'STANDBY'),

  // Infusion parameters
  obxNM(2,  'PUMP-FLOW',     'Flow rate',                 v('flow_rate_ml_h'),     'ml/h',      '0.1-1200'),
  obxNM(3,  'PUMP-VTBI',     'Volume to be infused',      v('vtbi_ml'),            'ml',         '0-9999'),
  obxNM(4,  'PUMP-INFUSED',  'Volume infused',            v('infused_volume_ml'),  'ml',         ''),

  // IV set sensor
  obxNM(5,  'PUMP-DROPS',    'Drop rate',                 v('drop_rate_per_min'),  'gotas/min',  ''),

  // Pressure / occlusion
  obxNM(6,  'PUMP-PRESS',    'Line pressure',             v('pressure_kpa'),       'kPa',        '30-160'),
  obxNM(7,  'PUMP-OCCL-THR', 'Occlusion threshold',       v('occlusion_threshold_kpa'), 'kPa',  '80-160'),

  // Air bubble and door
  obxST(8,  'PUMP-BUBBLE',   'Air bubble detected',       v('bubble_detected') ? 'YES' : 'NO'),
  obxST(9,  'PUMP-DOOR',     'Door open',                 v('door_open')       ? 'OPEN' : 'CLOSED'),

  // Battery
  obxNM(10, 'PUMP-BAT-V',    'Battery voltage',           v('battery_voltage_v'),     'V',   '6.8-8.4'),
  obxNM(11, 'PUMP-BAT-MIN',  'Battery autonomy remaining',v('battery_remaining_min'), 'min', ''),

  // Alarm summary
  obxST(12, 'PUMP-ALARM',    'Active alarm flags',        alarmStr),
];

tmp = lines.join('\r');
